\Rightarrow\qquad \begin{pmatrix} 7-2t \\ -3+5t \\ 1+t \end{pmatrix} &= \begin{pmatrix} 8+u \\ -1-4u \\ -1 \end{pmatrix}\\
\Rightarrow\qquad \begin{cases}
7-2t &= 8+u\\
-3+5t &= -1-4u\\
1+t &= -1
\end{cases}
\end{align*}

